import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z as z2 } from "npm:zod@^4.4.3";
var STOREFRONT_URL2 = "https://madeiraoriginals-cve6q.myshopify.com/api/2025-07/graphql.json";
var STOREFRONT_TOKEN2 = "bbcc49de92200adcd5c43d7f6f847485";
var QUERY2 = (
  /* GraphQL */
  `
  query GetProduct($handle: String!) {
    product(handle: $handle) {
      id
      title
      handle
      description
      productType
      tags
      priceRange { minVariantPrice { amount currencyCode } }
      images(first: 10) { edges { node { url altText } } }
      variants(first: 25) {
        edges {
          node {
            id
            title
            availableForSale
            price { amount currencyCode }
            selectedOptions { name value }
          }
        }
      }
    }
  }
`
);
var get_product_default = defineTool2({
  name: "get_product",
  title: "Get product",
  description: "Fetch a single Madeira Originals product by its handle, including full description, variants, and images.",
  inputSchema: {
    handle: z2.string().min(1).describe("Product handle, e.g. 'levada-walks-madeira-island-t-shirt'.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: async ({ handle }) => {
    const res = await fetch(STOREFRONT_URL2, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Shopify-Storefront-Access-Token": STOREFRONT_TOKEN2
      },
      body: JSON.stringify({ query: QUERY2, variables: { handle } })
    });
    if (!res.ok) {
      return { content: [{ type: "text", text: `Shopify error ${res.status}` }], isError: true };
    }
    const json = await res.json();
    const p = json.data?.product;
    if (!p) {
      return { content: [{ type: "text", text: `Product not found: ${handle}` }], isError: true };
    }
    const product = {
      title: p.title,
      handle: p.handle,
      description: p.description,
      productType: p.productType,
      tags: p.tags,
      priceFrom: `${p.priceRange.minVariantPrice.amount} ${p.priceRange.minVariantPrice.currencyCode}`,
      images: p.images.edges.map((e) => e.node.url),
      variants: p.variants.edges.map((e) => ({
        title: e.node.title,
        available: e.node.availableForSale,
        price: `${e.node.price.amount} ${e.node.price.currencyCode}`,
        options: e.node.selectedOptions
      })),
      url: `https://madeiraoriginals.pt/product/${p.handle}`
    };
    return {
      content: [{ type: "text", text: JSON.stringify(product, null, 2) }],
      structuredContent: { product }
    };
  }
});

